INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Body-Up','Body-Up','tríceps',ARRAY['abdominales','antebrazos'],'peso corporal','strength',ARRAY['Assume a plank position on the ground. You should be supporting your bodyweight on your toes and forearms, keeping your torso straight. Your forearms should be shoulder-width apart. This will be your starting position.','Pressing your palms firmly into the ground, extend through the elbows to raise your body from the ground. Keep your torso rigid as you perform the movement.','Slowly lower your forearms back to the ground by allowing the elbows to flex.','Repeat.'],'Assume a plank position on the ground. You should be supporting your bodyweight on your toes and forearms, keeping your torso straight. Your forearms should be shoulder-width apart. This will be your starting position. Pressing your palms firmly into the ground, extend through the elbows to raise your body from the ground. Keep your torso rigid as you perform the movement. Slowly lower your forearms back to the ground by allowing the elbows to flex. Repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Body-Up/0.jpg','exercisedb',true),('Body_Tricep_Press','Body Tricep Press','tríceps',ARRAY[]::text[],'peso corporal','strength',ARRAY['Position a bar in a rack at chest height.','Standing, take a shoulder width grip on the bar and step a yard or two back, feet together and arms extended so that you are leaning on the bar. This will be your starting position.','Begin by flexing the elbow, lowering yourself towards the bar.','Pause, and then reverse the motion by extending the elbows.','Progress from bodyweight by adding chains over your shoulders.'],'Position a bar in a rack at chest height. Standing, take a shoulder width grip on the bar and step a yard or two back, feet together and arms extended so that you are leaning on the bar. This will be your starting position. Begin by flexing the elbow, lowering yourself towards the bar. Pause, and then reverse the motion by extending the elbows. Progress from bodyweight by adding chains over your shoulders.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Body_Tricep_Press/0.jpg','exercisedb',true),('Bodyweight_Flyes','Bodyweight Flyes','pecho',ARRAY['abdominales','hombros','tríceps'],'barra curl EZ','strength',ARRAY['Position two equally loaded EZ bars on the ground next to each other. Ensure they are able to roll.','Assume a push-up position over the bars, supporting your weight on your toes and hands with your arms extended and body straight.','Place your hands on the bars. This will be your starting position.','Using a slow and controlled motion, move your hands away from the midline of your body, rolling the bars apart. Inhale during this portion of the motion.','After moving the bars as far apart as you can, return to the starting position by pulling them back together. Exhale as you perform this movement.'],'Position two equally loaded EZ bars on the ground next to each other. Ensure they are able to roll. Assume a push-up position over the bars, supporting your weight on your toes and hands with your arms extended and body straight. Place your hands on the bars. This will be your starting position. Using a slow and controlled motion, move your hands away from the midline of your body, rolling the bars apart. Inhale during this portion of the motion. After moving the bars as far apart as you can, return to the starting position by pulling them back together. Exhale as you perform this movement.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Flyes/0.jpg','exercisedb',true),('Bodyweight_Mid_Row','Bodyweight Mid Row','espalda media',ARRAY['bíceps','dorsales'],'otro','strength',ARRAY['Begin by taking a medium to wide grip on a pull-up apparatus with your palms facing away from you. From a hanging position, tuck your knees to your chest, leaning back and getting your legs over your side of the pull-up apparatus. This will be your starting position.','Beginning with your arms straight, flex the elbows and retract the shoulder blades to raise your body up until your legs contact the pull-up apparatus.','After a brief pause, return to the starting position.'],'Begin by taking a medium to wide grip on a pull-up apparatus with your palms facing away from you. From a hanging position, tuck your knees to your chest, leaning back and getting your legs over your side of the pull-up apparatus. This will be your starting position. Beginning with your arms straight, flex the elbows and retract the shoulder blades to raise your body up until your legs contact the pull-up apparatus. After a brief pause, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Mid_Row/0.jpg','exercisedb',true),('Bodyweight_Squat','Bodyweight Squat','cuádriceps',ARRAY['glúteos','isquiotibiales'],'peso corporal','strength',ARRAY['Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position.','Begin the movement by flexing your knees and hips, sitting back with your hips.','Continue down to full depth if you are able,and quickly reverse the motion until you return to the starting position. As you squat, keep your head and chest up and push your knees out.'],'Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position. Begin the movement by flexing your knees and hips, sitting back with your hips. Continue down to full depth if you are able,and quickly reverse the motion until you return to the starting position. As you squat, keep your head and chest up and push your knees out.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Squat/0.jpg','exercisedb',true),('Bodyweight_Walking_Lunge','Bodyweight Walking Lunge','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],NULL,'strength',ARRAY['Begin standing with your feet shoulder width apart and your hands on your hips.','Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.','Drive through the heel of your lead foot and extend both knees to raise yourself back up.','Step forward with your rear foot, repeating the lunge on the opposite leg.'],'Begin standing with your feet shoulder width apart and your hands on your hips. Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot. Drive through the heel of your lead foot and extend both knees to raise yourself back up. Step forward with your rear foot, repeating the lunge on the opposite leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Walking_Lunge/0.jpg','exercisedb',true),('Bosu_Ball_Cable_Crunch_With_Side_Bends','Bosu Ball Cable Crunch With Side Bends','abdominales',ARRAY[]::text[],'cable','strength',ARRAY['Connect a standard handle to each arm of a cable machine, and position them in the most downward position.','Grab a Bosu Ball and position it in front and center of the cable machine.','Lie down on the Bosu Ball with the small of your back arched around the ball. Your rear end should be close to the floor without touching it.','With both hands, reach back and grab the handle of each cable.','With your feet positioned in a wide stance, extend your arms straight out in front of you and in between your knees. Your hands should be at knee level.','Keep your arms straight and in-line with the upward angle of the cable. Elevate your torso in a crunching motion without dropping or bending your arms.','Maintain the rigid position with your arms. Slowly descend back to the starting position with your back arched around the Bosu Ball and your abdominals elongated.','Repeat the same series of movements to failure.','Once you reach failure, keep your abs tight and raise your torso into plank position so your back is elevated off the Bosu Ball.','Lower your arms down to your side; keep them straight. Start doing alternating side bends; reach for your heels! This finishing movement will focus on your obliques.'],'Connect a standard handle to each arm of a cable machine, and position them in the most downward position. Grab a Bosu Ball and position it in front and center of the cable machine. Lie down on the Bosu Ball with the small of your back arched around the ball. Your rear end should be close to the floor without touching it. With both hands, reach back and grab the handle of each cable. With your feet positioned in a wide stance, extend your arms straight out in front of you and in between your knees. Your hands should be at knee level. Keep your arms straight and in-line with the upward angle of the cable. Elevate your torso in a crunching motion without dropping or bending your arms. Maintain the rigid position with your arms. Slowly descend back to the starting position with your back arched around the Bosu Ball and your abdominals elongated. Repeat the same series of movements to failure. Once you reach failure, keep your abs tight and raise your torso into plank position so your back is elevated off the Bosu Ball. Lower your arms down to your side; keep them straight. Start doing alternating side bends; reach for your heels! This finishing movement will focus on your obliques.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bosu_Ball_Cable_Crunch_With_Side_Bends/0.jpg','exercisedb',true),('Bottoms-Up_Clean_From_The_Hang_Position','Bottoms-Up Clean From The Hang Position','antebrazos',ARRAY['bíceps','hombros'],'kettlebells','strength',ARRAY['Initiate the exercise by standing upright with a kettlebell in one hand.','Swing the kettlebell back forcefully and then reverse the motion forcefully. Crush the kettlebell handle as hard as possible and raise the kettlebell to your shoulder.'],'Initiate the exercise by standing upright with a kettlebell in one hand. Swing the kettlebell back forcefully and then reverse the motion forcefully. Crush the kettlebell handle as hard as possible and raise the kettlebell to your shoulder.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bottoms-Up_Clean_From_The_Hang_Position/0.jpg','exercisedb',true),('Bottoms_Up','Bottoms Up','abdominales',ARRAY[]::text[],'peso corporal','strength',ARRAY['Begin by lying on your back on the ground. Your legs should be straight and your arms at your side. This will be your starting position.','To perform the movement, tuck the knees toward your chest by flexing the hips and knees. Following this, extend your legs directly above you so that they are perpendicular to the ground. Rotate and elevate your pelvis to raise your glutes from the floor.','After a brief pause, return to the starting position.'],'Begin by lying on your back on the ground. Your legs should be straight and your arms at your side. This will be your starting position. To perform the movement, tuck the knees toward your chest by flexing the hips and knees. Following this, extend your legs directly above you so that they are perpendicular to the ground. Rotate and elevate your pelvis to raise your glutes from the floor. After a brief pause, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bottoms_Up/0.jpg','exercisedb',true),('Box_Jump_Multiple_Response','Box Jump (Multiple Response)','isquiotibiales',ARRAY['abductores','aductores','pantorrillas','glúteos','cuádriceps'],'otro','plyometrics',ARRAY['Assume a relaxed stance facing the box or platform approximately an arm''''s length away. Arms should be down at the sides and legs slightly bent.','Using the arms to aid in the initial burst, jump upward and forward, landing with feet simultaneously on top of the box or platform.','Immediately drop or jump back down to the original starting place; then repeat the sequence.'],'Assume a relaxed stance facing the box or platform approximately an arm''s length away. Arms should be down at the sides and legs slightly bent. Using the arms to aid in the initial burst, jump upward and forward, landing with feet simultaneously on top of the box or platform. Immediately drop or jump back down to the original starting place; then repeat the sequence.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Box_Jump_Multiple_Response/0.jpg','exercisedb',true);